const resp = $input.first().json;
const rawText = (resp.content && resp.content[0] && resp.content[0].text) || '';
const text = rawText.toLowerCase().trim();
let persona = 'guide';
if (text.includes('architect')) persona = 'architect';
else if (text.includes('programs') || text.startsWith('program')) persona = 'programs';
else if (text.includes('guide')) persona = 'guide';
const cfg = $('Config').first().json;
const userMsg = (cfg.userMessage || '').toLowerCase();

// STEP 1 — Deterministic output-type override. Beats the router AND stickiness.
// If the user's message contains an explicit output-type signal, force the correct
// persona. This prevents Haiku from misclassifying 'I want a pitch deck on this' as
// guide just because the word 'this' is conversational.
const programsSignals = /\b(pitch\s*deck|pitch\s*slide|slide\s*deck|country\s*proposal|adoption\s*proposal|inter-departmental|ministerial\s*brief|outreach\s*playbook|stakeholder\s*map|rollout\s*plan|pitch\s+(?:to|for|on|about))\b/;
const architectSignals = /\b(advisory\s*note|technical\s*note|tech\s*note|technical\s*advisory|technical\s*scope|feature\s*spec|api\s*spec|specification|implementation\s*review|architecture\s*(?:note|doc|diagram))\b/;
if (programsSignals.test(userMsg)) {
  persona = 'programs';
} else if (architectSignals.test(userMsg)) {
  persona = 'architect';
} else {
  // STEP 2 — Stickiness. Only applies when no explicit output signal fires.
  // Keeps follow-up turns on the prior persona for continuation phrases like
  // 'revise slide 3', 'tighten this', 'yes do it'.
  const wantsGuideTopic = /\b(what is|what\u2019s|how does|why would|explain|walk me through|i'?m new|which tier)\b/.test(userMsg);
  if (cfg.lastPersona && (cfg.lastPersona === 'architect' || cfg.lastPersona === 'programs') && !wantsGuideTopic) {
    persona = cfg.lastPersona;
  }
}

let personaPrompt;
if (persona === 'architect') personaPrompt = cfg.architectPrompt;
else if (persona === 'programs') personaPrompt = cfg.programsPrompt;
else personaPrompt = cfg.guidePrompt;
return [{ json: { persona, personaPrompt, userMessage: cfg.userMessage, conversationId: cfg.conversationId, context: cfg.context, history: cfg.history } }];

const parse = $('Parse Router').first().json;
const qdrantResp = $input.first().json;
const hits = (qdrantResp && qdrantResp.result) || [];
const retrievedContext = hits.map((hit, i) => {
  const source = (hit.payload && hit.payload.source) || 'unknown';
  const text = (hit.payload && hit.payload.text) || '';
  return '[' + (i+1) + '] Source: ' + source + '\n' + text;
}).join('\n\n---\n\n');
const retrievedBlock = retrievedContext || '(no relevant documents found — answer from general principles and label clearly.)';
let contextBlock = '';
const ctx = parse.context;
if (ctx && (ctx.currentPath || ctx.currentTitle)) {
  contextBlock = '\n\n# Current user context\nThe user is chatting from the vc.infra web application. Right now they are viewing:\n- Page path: ' + (ctx.currentPath || 'unknown') + '\n- Page title: ' + (ctx.currentTitle || 'unknown') + '\n\nIf the user asks navigational or location-specific questions ("what is this page", "where should I go next"), use this context. Otherwise answer their question directly — do not force-mention the current page.\n';
}
const systemPrompt = parse.personaPrompt + contextBlock + '\n\n# Retrieved context from CDPI corpus\n\n' + retrievedBlock;
// Build the Anthropic messages array: prior history (sanitized) + this turn's user message.
const rawHistory = Array.isArray(parse.history) ? parse.history : [];
const validHistory = rawHistory.filter(m => m && (m.role === 'user' || m.role === 'assistant') && typeof m.content === 'string');
const messages = validHistory.concat([{ role: 'user', content: parse.userMessage }]);
return [{ json: { systemPrompt, messages, userMessage: parse.userMessage, persona: parse.persona, conversationId: parse.conversationId } }];
